SELECT h.*, ste.site_nm AS site_nm, prd.prod_nm AS prod_nm, usr.user_nm AS chg_user_nm FROM pdh_prod_content_chg_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN pd_prod prd ON prd.prod_id = h.prod_id LEFT JOIN sy_user usr ON usr.user_id = h.chg_user_id
ORDER BY h.hist_id ASC ORDER BY h.hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

